+    #[test]
+    fn rect_center_basic() {
+        let r = Rect::new(10, 20, 30, 40);
+        let (cx, cy) = rect_center(r);
+        // center x = 10 + (30-1)/2 = 10 + 14 = 24
+        // center y = 20 + (40-1)/2 = 20 + 19 = 39
+        assert_eq!(cx, 24);
+        assert_eq!(cy, 39);
+    }
